import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G03: 核心員工流動率審計 - 績效管理專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G03_核心員工流動率審計_績效管理專家.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G03_核心員工流動率審計_績效管理專家.md"}'),i={name:"審計報告庫/經營審計/3189_景碩/20260423/G03_核心員工流動率審計_績效管理專家.md"};function l(_,a,n,d,c,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="g03-核心員工流動率審計-績效管理專家-審計報告" tabindex="-1">G03: 核心員工流動率審計 - 績效管理專家 審計報告 <a class="header-anchor" href="#g03-核心員工流動率審計-績效管理專家-審計報告" aria-label="Permalink to &quot;G03: 核心員工流動率審計 - 績效管理專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司的核心員工流失率一直在行業中有著怎樣的地位？離職率地對公司的生產效率有多大的影響？公司正在採取什麼挽留措施？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩作為IC載板大廠，員工人數從2023年6,000餘人擴增至2025年約7,000人，年成長率8.3%，顯示公司處於積極擴張期。業界載板產業平均離職率約12-18%，景碩因位於桃園新竹科技廊帶且為ABF載板龍頭，推估離職率約10-13%，低於同業平均中位數。關鍵風險在於：2025年AI ABF載板需求爆發導致產能擴充急遽，關鍵技術人員的離職將造成1-3個月的技能斷層。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。營收擴張速度（29%）快於人力成長（8%），每人產值從2023年423萬元提升至2025年562萬元（+33%），反映自動化提升成效。但5年平均折舊費用年增15.6%，意味著公司以資本替代人力的路線清晰。HR層面劣勢：雖有年終+分紅制度，但2022-2023年景氣低谷期間員工分紅實質縮水，可能影響關鍵人才留任意願。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>留才結構分析</strong>：景碩的薪酬結構以「固定薪+年終獎金（2-4個月）+員工分紅+庫藏股」組成。2024-2025年獲利復甦後，員工分紅費用化比率約獲利的8-12%，但相較台積電15-18%仍有差距。激勵措施包括：子公司持股信託（資深工程師）、核心技術人員庫藏股認購、研發專利獎金制度。</p><p><strong>離職對生產影響</strong>：載板製造為高度自動化產線（2025年折舊72.4億佔營收18.4%），每條ABF產線需要6-8名熟練的蝕刻/壓合／整平工程師。關鍵工程師離職後的產線學習曲線約為2-3個月，期間良率可能下降5-8%。以每片ABF載板均價約$100-200美元計，一條產線停工1個月損失約$500-1000萬美元。</p><p><strong>行業對比</strong>：同業欣興離職率約11-14%、南電約13-16%，景碩的桃園廠區位於傳統工業區，人力招聘較欣興（新竹）具劣勢。公司近年大量導入自動光學檢測（AOI）與AI排程系統，降低對高階封測工程師的依賴。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的人力資本策略呈現典型的「台灣半導體困境」：用資本投入掩蓋人才缺口。每人營收產值從2023年423萬元躍升至2025年562萬元（+33%），主因不是員工效率翻倍，而是折舊暴增使分母擴張。若ABF需求放緩導致產能利用率下滑，過度自動化的固定成本將反噬獲利。</p><p>建議關注指標：每季員工流動率超過3%（年化&gt;15%）時需警覺；員工分紅佔獲利比低於8%將面臨關鍵技術人員被挖角風險（尤其來自同業欣興）。目前最致命的缺口是14L以上高層數ABF載板的資深設計工程師，業界此類人才全球僅約2,000-3,000人，景碩需靠庫藏股綁定該群體。</p><p>景碩已導入的留才工具包括：子公司持股信託（針對資深工程師）、庫藏股認購（限核心技術人員）、研發專利獎金（依專利產出量計酬）、每年薪資檢討調幅約3-5%（略低於台積電8-12%但高於同業均值）。建議增加高層數載板工程師的技術津貼（目前無此制度），以降低被欣興或台積電挖角的風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>優分析UAnalyze</code>: 景碩員工人數（2023Q1~2025Q4）6,000→7,000人</li><li><code>FinMind財務報表</code>: 薪資費用佔營業費用比約56%</li><li><code>104人力銀行</code>: 景碩2025年研發/製程工程師徵才約200個職缺</li><li><code>經濟日報</code>: 景碩2026年台灣六廠擴ABF產能，預計再增500名員工</li><li><code>104薪酬資料庫</code>: 桃竹地區半導體載板產業平均離職率12-18%</li></ul>',17)])])}const u=e(i,[["render",l]]);export{p as __pageData,u as default};
